import{_ as a,o as s,c as n,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse(`{"title":"Nix","description":"","frontmatter":{"summary":"Install OpenSoul declaratively with Nix","read_when":["You want reproducible, rollback-able installs","You're already using Nix/NixOS/Home Manager","You want everything pinned and managed declaratively"],"title":"Nix"},"headers":[],"relativePath":"install/nix.md","filePath":"install/nix.md","lastUpdated":null}`),t={name:"install/nix.md"};function l(o,e,p,r,c,d){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="nix-installation" tabindex="-1"><a class="header-anchor" href="#nix-installation">#</a> Nix Installation</h1><p>The recommended way to run OpenSoul with Nix is via <strong><a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">nix-opensoul</a></strong> — a batteries-included Home Manager module.</p><h2 id="quick-start" tabindex="-1"><a class="header-anchor" href="#quick-start">#</a> Quick Start</h2><p>Paste this to your AI agent (Claude, Cursor, etc.):</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to set up nix-opensoul on my Mac.</span></span>
<span class="line"><span>Repository: github:opensoul/nix-opensoul</span></span>
<span class="line"><span></span></span>
<span class="line"><span>What I need you to do:</span></span>
<span class="line"><span>1. Check if Determinate Nix is installed (if not, install it)</span></span>
<span class="line"><span>2. Create a local flake at ~/code/opensoul-local using templates/agent-first/flake.nix</span></span>
<span class="line"><span>3. Help me create a Telegram bot (@BotFather) and get my chat ID (@userinfobot)</span></span>
<span class="line"><span>4. Set up secrets (bot token, Anthropic key) - plain files at ~/.secrets/ is fine</span></span>
<span class="line"><span>5. Fill in the template placeholders and run home-manager switch</span></span>
<span class="line"><span>6. Verify: launchd running, bot responds to messages</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Reference the nix-opensoul README for module options.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><blockquote><p><strong>📦 Full guide: <a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">github.com/opensoul/nix-opensoul</a></strong></p><p>The nix-opensoul repo is the source of truth for Nix installation. This page is just a quick overview.</p></blockquote><h2 id="what-you-get" tabindex="-1"><a class="header-anchor" href="#what-you-get">#</a> What you get</h2><ul><li>Gateway + macOS app + tools (whisper, spotify, cameras) — all pinned</li><li>Launchd service that survives reboots</li><li>Plugin system with declarative config</li><li>Instant rollback: <code>home-manager switch --rollback</code></li></ul><hr><h2 id="nix-mode-runtime-behavior" tabindex="-1"><a class="header-anchor" href="#nix-mode-runtime-behavior">#</a> Nix Mode Runtime Behavior</h2><p>When <code>OPENSOUL_NIX_MODE=1</code> is set (automatic with nix-opensoul):</p><p>OpenSoul supports a <strong>Nix mode</strong> that makes configuration deterministic and disables auto-install flows. Enable it by exporting:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_NIX_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>On macOS, the GUI app does not automatically inherit shell env vars. You can also enable Nix mode via defaults:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">defaults</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul.nixMode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -bool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="config-state-paths" tabindex="-1"><a class="header-anchor" href="#config-state-paths">#</a> Config + state paths</h3><p>OpenSoul reads JSON5 config from <code>OPENSOUL_CONFIG_PATH</code> and stores mutable data in <code>OPENSOUL_STATE_DIR</code>.</p><ul><li><code>OPENSOUL_STATE_DIR</code> (default: <code>~/.opensoul</code>)</li><li><code>OPENSOUL_CONFIG_PATH</code> (default: <code>$OPENSOUL_STATE_DIR/opensoul.json</code>)</li></ul><p>When running under Nix, set these explicitly to Nix-managed locations so runtime state and config stay out of the immutable store.</p><h3 id="runtime-behavior-in-nix-mode" tabindex="-1"><a class="header-anchor" href="#runtime-behavior-in-nix-mode">#</a> Runtime behavior in Nix mode</h3><ul><li>Auto-install and self-mutation flows are disabled</li><li>Missing dependencies surface Nix-specific remediation messages</li><li>UI surfaces a read-only Nix mode banner when present</li></ul><h2 id="packaging-note-macos" tabindex="-1"><a class="header-anchor" href="#packaging-note-macos">#</a> Packaging note (macOS)</h2><p>The macOS packaging flow expects a stable Info.plist template at:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apps/macos/Sources/OpenSoul/Resources/Info.plist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/package-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/package-mac-app.sh</code></a> copies this template into the app bundle and patches dynamic fields (bundle ID, version/build, Git SHA, Sparkle keys). This keeps the plist deterministic for SwiftPM packaging and Nix builds (which do not rely on a full Xcode toolchain).</p><h2 id="related" tabindex="-1"><a class="header-anchor" href="#related">#</a> Related</h2><ul><li><a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">nix-opensoul</a> — full setup guide</li><li><a href="/docs/start/wizard">Wizard</a> — non-Nix CLI setup</li><li><a href="/docs/install/docker">Docker</a> — containerized setup</li></ul>`,27)])])}const b=a(t,[["render",l]]);export{u as __pageData,b as default};
